  ('aboriginal-a5729396-moex-00036', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '專科以上學校申請設立原住民專班，依法應有的行政組織配置，下列敘述何者錯誤？', '["應置行政人員至少1人", "應置主管1人，由該專班專任教師擔任，綜理專班事務", "應聘任具原住民身分之專任教師至少1人", "原住民專班之設立，以原住民族委員會建議類別優先辦理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00037', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依照原住民族工作權保障法的規定，政府應依原住民群體工作習性，輔導原住民設立各種性質之原住民合 作社，以開發各項工作機會。原住民合作社之籌設、社員之培訓及營運發展等事項，應由各目的事業主管 機關輔導辦理。前述原住民合作社，指原住民社員超過該合作社社員總人數百分之多少？', '["50%", "70%", "80%", "100%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00038', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '原住民族傳統智慧創作保護條例是為保護原住民族之傳統智慧創作，促進原住民族文化發展而訂定。請問 本法的主管機關為何？', '["文化部文化資產局", "原住民族委員會", "經濟部商業發展署", "智慧財產及商業法院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00039', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依照原住民族傳統智慧創作保護條例的規定，經認定為智慧創作者，下列有關智慧創作專用權取得的敘述， 何者錯誤？', '["智慧創作經認定屬於申請人者，應准予登記，並自登記之日起，由申請人取得智慧創作專用權", "智慧創作專用權人之部落名稱得自由變更", "智慧創作經認定屬於申請人及其他特定原住民族或部落者，自登記之日起，由申請人及其他特定原住民 族或部落共同取得智慧創作專用權", "智慧創作不能認定屬於特定原住民族或部落者，應登記為全部原住民族，並自登記之日起，由全部原住 民族取得智慧創作專用權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00040', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '為處理原住民保留地禁伐補償事宜，進而達成維護國土保安、涵養水資源、綠化環境、自然生態保育及因 應氣候變遷、減輕天然災害之目標，特別制定原住民保留地禁伐補償條例。自114年起依該條例核發禁伐 補償金額度為何？', '["每年每公頃新臺幣1萬元", "每年每公頃新臺幣3萬元", "每年每公頃新臺幣6萬元", "每年每公頃新臺幣9萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
